/**
 * opencode-ish TUI for pi.
 *
 * Drop this file in .pi/extensions/ and run `/reload`.
 * It customizes pi's header, footer, editor rails, working indicator,
 * thinking label, and applies the project-local `opencode` theme.
 */

import { basename } from "node:path";
import { CustomEditor, type ExtensionAPI, type ExtensionContext, type KeybindingsManager, type Theme } from "@earendil-works/pi-coding-agent";
import { truncateToWidth, visibleWidth, type EditorTheme, type TUI } from "@earendil-works/pi-tui";

const THEME_NAME = "opencode";
const STATUS_KEY = "opencode-ui";
const HELP_WIDGET_KEY = "opencode-ui-help";

type UiState = "ready" | "working" | "queued";

let enabled = process.env.PI_OPENCODE_UI !== "0";
let autoTheme = process.env.PI_OPENCODE_UI_THEME !== "0";
let previousThemeName: string | undefined;
let state: UiState = "ready";

function projectName(cwd: string): string {
	return basename(cwd) || cwd;
}

function formatCount(value: number): string {
	if (value >= 1_000_000) return `${(value / 1_000_000).toFixed(1)}m`;
	if (value >= 1_000) return `${(value / 1_000).toFixed(1)}k`;
	return `${value}`;
}

function formatModel(ctx: ExtensionContext): string {
	if (!ctx.model) return "no-model";
	return `${ctx.model.provider}/${ctx.model.id}`;
}

function sessionTotals(ctx: ExtensionContext): { input: number; output: number; cost: number } {
	let input = 0;
	let output = 0;
	let cost = 0;

	for (const entry of ctx.sessionManager.getBranch()) {
		if (entry.type !== "message" || entry.message.role !== "assistant") continue;
		const usage = entry.message.usage;
		input += usage?.input ?? 0;
		output += usage?.output ?? 0;
		cost += usage?.cost?.total ?? 0;
	}

	return { input, output, cost };
}

function fitLeftRight(left: string, right: string, width: number): string {
	if (width <= 0) return "";
	const rightWidth = visibleWidth(right);
	const maxLeft = Math.max(0, width - rightWidth - 1);
	const fittedLeft = visibleWidth(left) > maxLeft ? truncateToWidth(left, maxLeft, "…") : left;
	const gap = Math.max(1, width - visibleWidth(fittedLeft) - rightWidth);
	return truncateToWidth(`${fittedLeft}${" ".repeat(gap)}${right}`, width, "");
}

function rule(width: number, left: string, right: string, border: (text: string) => string): string {
	if (width <= 0) return "";
	const leftPart = border("─") + left;
	const rightPart = right ? right + border("─") : border("─");
	const fillWidth = Math.max(0, width - visibleWidth(leftPart) - visibleWidth(rightPart));
	return truncateToWidth(leftPart + border("─".repeat(fillWidth)) + rightPart, width, "");
}

function stateSegment(theme: Theme): string {
	switch (state) {
		case "working":
			return `${theme.fg("accent", "●")} ${theme.fg("muted", "working")}`;
		case "queued":
			return `${theme.fg("warning", "●")} ${theme.fg("muted", "queued")}`;
		case "ready":
			return `${theme.fg("success", "●")} ${theme.fg("muted", "ready")}`;
	}
}

function setState(ctx: ExtensionContext, next: UiState): void {
	state = next;
	if (ctx.mode === "tui") ctx.ui.setStatus(STATUS_KEY, next);
}

function tryApplyTheme(ctx: ExtensionContext): boolean {
	if (!autoTheme || ctx.mode !== "tui") return false;
	if (ctx.ui.theme.name === THEME_NAME) return true;
	const theme = ctx.ui.getTheme(THEME_NAME);
	if (!theme) return false;

	if (!previousThemeName && ctx.ui.theme.name && ctx.ui.theme.name !== THEME_NAME) {
		previousThemeName = ctx.ui.theme.name;
	}

	return ctx.ui.setTheme(theme).success;
}

function deferTheme(ctx: ExtensionContext, attempts = 8): void {
	if (!autoTheme || ctx.mode !== "tui") return;
	setTimeout(() => {
		if (!enabled || tryApplyTheme(ctx) || attempts <= 1) return;
		deferTheme(ctx, attempts - 1);
	}, 50);
}

class OpencodeEditor extends CustomEditor {
	constructor(
		tui: TUI,
		theme: EditorTheme,
		keybindings: KeybindingsManager,
		private readonly getTheme: () => Theme,
	) {
		super(tui, theme, keybindings, { paddingX: 1, autocompleteMaxVisible: 8 });
	}

	render(width: number): string[] {
		const lines = super.render(width);
		if (lines.length < 2 || width < 8) return lines;

		const theme = this.getTheme();
		const mode = this.getText().trimStart().startsWith("!") ? " shell " : " chat ";
		const chars = visibleWidth(this.getText());

		lines[0] = rule(
			width,
			` ${theme.fg("accent", "opencode")} ${theme.fg("dim", "pi")} `,
			` ${theme.fg("dim", "enter send")} `,
			this.borderColor,
		);
		lines[lines.length - 1] = rule(
			width,
			` ${theme.fg("muted", mode)} `,
			` ${theme.fg("dim", `${chars} chars`)} `,
			this.borderColor,
		);

		return lines;
	}
}

function applyChrome(ctx: ExtensionContext): void {
	if (ctx.mode !== "tui") return;

	tryApplyTheme(ctx);
	deferTheme(ctx);
	ctx.ui.setTitle(`opencode · ${projectName(ctx.cwd)}`);
	ctx.ui.setToolsExpanded(false);
	ctx.ui.setHiddenThinkingLabel("thinking collapsed");
	ctx.ui.setWorkingMessage("working");
	ctx.ui.setWorkingIndicator({
		frames: [
			ctx.ui.theme.fg("dim", "·"),
			ctx.ui.theme.fg("muted", "•"),
			ctx.ui.theme.fg("accent", "●"),
			ctx.ui.theme.fg("muted", "•"),
		],
		intervalMs: 120,
	});

	ctx.ui.setHeader((_tui, theme) => ({
		invalidate() {},
		render(width: number): string[] {
			const top = rule(
				width,
				` ${theme.fg("accent", theme.bold("opencode"))} ${theme.fg("dim", "style for pi")} `,
				` ${theme.fg("dim", "/opencode-ui off")} `,
				(text) => theme.fg("borderMuted", text),
			);
			const body = fitLeftRight(
				`  ${theme.fg("accent", "▸")} ${theme.fg("text", projectName(ctx.cwd))}`,
				theme.fg("muted", formatModel(ctx)),
				width,
			);
			const hint = truncateToWidth(
				theme.fg("dim", "  ctrl+l model  ·  ctrl+p cycle  ·  esc interrupt  ·  /reload after edits"),
				width,
				"…",
			);
			return [top, body, hint];
		},
	}));

	ctx.ui.setFooter((tui, theme, footerData) => {
		const unsub = footerData.onBranchChange(() => tui.requestRender());

		return {
			dispose: unsub,
			invalidate() {},
			render(width: number): string[] {
				const branch = footerData.getGitBranch();
				const totals = sessionTotals(ctx);
				const usage = ctx.getContextUsage();
				const context = usage?.percent == null ? "ctx --" : `ctx ${Math.round(usage.percent)}%`;
				const thinking = `think ${pi.getThinkingLevel()}`;

				const otherStatuses = Array.from(footerData.getExtensionStatuses())
					.filter(([key]) => key !== STATUS_KEY)
					.map(([, value]) => value);

				const leftParts = [
					`${theme.fg("accent", "opencode")} ${theme.fg("dim", "pi")}`,
					stateSegment(theme),
					theme.fg("muted", projectName(ctx.cwd)),
					branch ? theme.fg("dim", `git:${branch}`) : undefined,
					...otherStatuses,
				].filter(Boolean);

				const rightParts = [
					theme.fg("muted", formatModel(ctx)),
					theme.fg("dim", thinking),
					theme.fg("dim", context),
					theme.fg("dim", `↑${formatCount(totals.input)} ↓${formatCount(totals.output)}`),
					theme.fg("dim", `$${totals.cost.toFixed(3)}`),
				];

				return [fitLeftRight(leftParts.join(theme.fg("dim", "  ·  ")), rightParts.join("  "), width)];
			},
		};
	});

	ctx.ui.setWidget(
		HELP_WIDGET_KEY,
		(_tui, theme) => ({
			invalidate() {},
			render(width: number): string[] {
				return [
					truncateToWidth(
						theme.fg("dim", "  esc stop  ·  ctrl+o tools  ·  ctrl+t thinking  ·  @file attach  ·  !cmd run"),
						width,
						"…",
					),
				];
			},
		}),
		{ placement: "belowEditor" },
	);

	ctx.ui.setEditorComponent((tui, theme, keybindings) => new OpencodeEditor(tui, theme, keybindings, () => ctx.ui.theme));
	setState(ctx, state);
}

function restoreChrome(ctx: ExtensionContext, restoreTheme = true): void {
	if (ctx.mode !== "tui") return;

	ctx.ui.setHeader(undefined);
	ctx.ui.setFooter(undefined);
	ctx.ui.setWidget(HELP_WIDGET_KEY, undefined);
	ctx.ui.setEditorComponent(undefined);
	ctx.ui.setWorkingIndicator();
	ctx.ui.setWorkingMessage();
	ctx.ui.setHiddenThinkingLabel();
	ctx.ui.setStatus(STATUS_KEY, undefined);
	ctx.ui.setTitle(`pi · ${projectName(ctx.cwd)}`);

	if (restoreTheme && previousThemeName && ctx.ui.theme.name === THEME_NAME) {
		ctx.ui.setTheme(previousThemeName);
	}
}

export default function opencodeTui(pi: ExtensionAPI) {
	pi.on("session_start", async (_event, ctx) => {
		if (!enabled) return;
		state = "ready";
		applyChrome(ctx);
	});

	pi.on("resources_discover", async (_event, ctx) => {
		if (enabled) deferTheme(ctx);
	});

	pi.on("agent_start", async (_event, ctx) => {
		if (enabled) setState(ctx, "working");
	});

	pi.on("turn_end", async (_event, ctx) => {
		if (!enabled) return;
		setState(ctx, ctx.hasPendingMessages() ? "queued" : "ready");
	});

	pi.on("agent_end", async (_event, ctx) => {
		if (enabled) setState(ctx, ctx.hasPendingMessages() ? "queued" : "ready");
	});

	pi.on("model_select", async (_event, ctx) => {
		if (enabled && ctx.mode === "tui") ctx.ui.setStatus(STATUS_KEY, state);
	});

	pi.on("thinking_level_select", async (_event, ctx) => {
		if (enabled && ctx.mode === "tui") ctx.ui.setStatus(STATUS_KEY, state);
	});

	pi.on("session_shutdown", async (_event, ctx) => {
		restoreChrome(ctx, false);
	});

	pi.registerCommand("opencode-ui", {
		description: "Toggle the opencode-style pi TUI chrome. Usage: /opencode-ui [on|off|theme-on|theme-off|status]",
		handler: async (args, ctx) => {
			const action = args.trim().toLowerCase();

			if (!action || action === "status") {
				ctx.ui.notify(
					`opencode UI: ${enabled ? "on" : "off"}; theme: ${autoTheme ? "on" : "off"}; state: ${state}`,
					"info",
				);
				return;
			}

			if (action === "on") {
				enabled = true;
				state = "ready";
				applyChrome(ctx);
				ctx.ui.notify("opencode-style UI enabled", "info");
				return;
			}

			if (action === "off") {
				enabled = false;
				restoreChrome(ctx);
				ctx.ui.notify("opencode-style UI disabled", "info");
				return;
			}

			if (action === "theme-on") {
				autoTheme = true;
				if (!tryApplyTheme(ctx)) deferTheme(ctx);
				ctx.ui.notify("opencode theme auto-apply enabled", "info");
				return;
			}

			if (action === "theme-off") {
				autoTheme = false;
				if (previousThemeName && ctx.mode === "tui" && ctx.ui.theme.name === THEME_NAME) {
					ctx.ui.setTheme(previousThemeName);
				}
				ctx.ui.notify("opencode theme auto-apply disabled", "info");
				return;
			}

			ctx.ui.notify("Usage: /opencode-ui [on|off|theme-on|theme-off|status]", "error");
		},
	});
}

