  ) {
    super(tui, theme, keybindings, { paddingX: 1, autocompleteMaxVisible: 8 });
  }

  render(width: number): string[] {
    const lines = super.render(width);
    if (lines.length < 2 || width < 8) return lines;

    const theme = this.getTheme();
    const mode = this.getText().trimStart().startsWith('!') ? ' shell ' : ' chat ';
    const chars = visibleWidth(this.getText());

    lines[0] = rule(
      width,
      ` ${theme.fg('accent', 'opencode')} ${theme.fg('dim', 'pi')} `,
      ` ${theme.fg('dim', 'enter send')} `,
      this.borderColor
    );
    lines[lines.length - 1] = rule(
      width,
      ` ${theme.fg('muted', mode)} `,
      ` ${theme.fg('dim', `${chars} chars`)} `,
      this.borderColor
    );

    return lines;
  }
}

